<span class="line">    pictures<span class="token punctuation">.</span>add<span class="token punctuation">(</span>File<span class="token punctuation">(</span><span class="token string">&quot;截图.png&quot;</span><span class="token punctuation">,</span> <span class="token number">512</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
